useEffect(() => {
  // Dashboard general
  fetch("http://localhost:3001/admin/dashboard")
    .then((res) => res.json())
    .then((json) => setData(json))
    .catch((err) => console.error("Error al cargar dashboard:", err));

  // Ventas mensuales
  fetch("http://localhost:3001/admin/ventas-mensuales")
    .then((res) => res.json())
    .then((rows) => {
      setVentasData({
        labels: rows.map((r) => `Mes ${r.mes}`),
        datasets: [
          {
            label: "Ventas Mensuales",
            data: rows.map((r) => r.total),
            backgroundColor: "#4CAF50",
          },
        ],
      });
    });

  // Productos más vendidos
  fetch("http://localhost:3001/admin/productos-mas-vendidos")
    .then((res) => res.json())
    .then((rows) => {
      setProductosData({
        labels: rows.map((r) => r.nombre),
        datasets: [
          {
            data: rows.map((r) => r.total_vendidos),
            backgroundColor: ["#2196F3", "#FF9800", "#F44336", "#9C27B0", "#00BCD4"],
          },
        ],
      });
    });
}, []);
